class Solution {
public:
    vector<vector<int>> largeGroupPositions(string s) {
        vector<vector<int>> result;
        int start = 0;
        for (int i = 1; i < s.size(); i++) {
            if (s[i] != s[i - 1]) {
                if (i - start >= 3) {
                    result.push_back({start, i - 1});
                }
                start = i;
            }
        }
        if (s.size() - start >= 3) {
            result.push_back({start, s.size() - 1});
        }
        return result;
    }
};
